struct Node { int val; Node *prev; Node *next;};

void mergeSort(Node *head) {
    if (head == nullptr || head->next == nullptr) return ;
    Node *mid = findMid(head);
    Node *midNext = mid->next;
    mid->next = nullptr;
    mergeSort(head);
    mergeSort(midNext);
    Node *merged = merge(head, midNext);
    head = merged;
}

Node *merge(Node *l, Node *r) {
    if (l == nullptr)
        return r;
    if (r == nullptr)
        return l;
    if (l->val <= r->val){
        l->next = merge(l->next, r);
        return l;
    }
    Node *merged = new Node{l->val};
    merged->next = merge(l->next, r);
    return merged;
}

